import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { courierApi, orderApi } from '../../api/client';
import { useCourierLocation } from '../../hooks/useTracking';

export default function CourierDashboard() {
  const [stats,   setStats]   = useState(null);
  const [online,  setOnline]  = useState(false);
  const [orders,  setOrders]  = useState([]);
  const { active, start, stop } = useCourierLocation();

  useEffect(() => {
    courierApi.getStats().then(({ data }) => {
      setStats(data.data);
      setOnline(data.data.isOnline);
    });
    orderApi.getMyOrders().then(({ data }) => setOrders(data.data?.content || []));
  }, []);

  const toggleOnline = async () => {
    try {
      await courierApi.setStatus(!online);
      setOnline(!online);
      if (!online) start(); else stop();
      toast.success(online ? 'Siz offline bo\'ldingiz' : 'Siz online bo\'ldingiz 🟢');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xato');
    }
  };

  const payout = async () => {
    try {
      await courierApi.requestPayout();
      toast.success('To\'lov so\'rovi yuborildi!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xato');
    }
  };

  return (
    <div style={s.page}>
      <div style={s.topRow}>
        <div style={s.title}>Kuryer paneli</div>
        <button
          style={{ ...s.onlineBtn, background: online ? '#0D7A6A' : '#888' }}
          onClick={toggleOnline}
        >
          {online ? '🟢 ONLINE' : '⭕ OFFLINE'}
        </button>
      </div>

      {stats && (
        <div style={s.grid}>
          <StatCard label="Bugungi buyurtma" value={stats.todayOrders} />
          <StatCard label="Bugungi daromad" value={`${(stats.todayEarnings||0).toLocaleString()} so'm`} amber />
          <StatCard label="Reyting" value={`★ ${stats.rating}`} />
          <StatCard label="Balans" value={`${(stats.balance||0).toLocaleString()} so'm`} />
        </div>
      )}

      {active && (
        <div style={s.gpsInfo}>
          📡 GPS joylashuv yuborilmoqda (har 30 soniyada)
        </div>
      )}

      <div style={s.card}>
        <div style={s.sectionTitle}>So'nggi buyurtmalar</div>
        {orders.length === 0 ? (
          <p style={{ color:'#6b8080', fontSize:13 }}>Hali buyurtma yo'q</p>
        ) : (
          orders.slice(0,10).map((o) => (
            <div key={o.id} style={s.orderRow}>
              <div>
                <div style={s.orderId}>#{o.id?.slice(0,8).toUpperCase()}</div>
                <div style={s.orderMeta}>{o.deliveryAddress?.slice(0,40)}</div>
              </div>
              <div style={s.orderFee}>{o.totalFee?.toLocaleString()} so'm</div>
            </div>
          ))
        )}
      </div>

      <button style={s.payoutBtn} onClick={payout}>
        💸 To'lov so'rash (min 50,000 so'm)
      </button>
    </div>
  );
}

function StatCard({ label, value, amber }) {
  return (
    <div style={{ background:'#fff', border:'1px solid rgba(13,122,106,0.15)',
                  borderRadius:12, padding:'14px 16px', textAlign:'center' }}>
      <div style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:22,
                    color: amber ? '#EF9F27' : '#0D7A6A' }}>{value}</div>
      <div style={{ fontSize:12, color:'#6b8080', marginTop:3 }}>{label}</div>
    </div>
  );
}

const s = {
  page:       { maxWidth:680, margin:'0 auto', padding:16 },
  topRow:     { display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:16 },
  title:      { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:20, color:'#1a2e2a' },
  onlineBtn:  { color:'#fff', border:'none', borderRadius:20, padding:'8px 18px',
                fontSize:13, fontWeight:700, cursor:'pointer' },
  grid:       { display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:16 },
  gpsInfo:    { background:'#E1F5EE', border:'1px solid rgba(13,122,106,0.2)',
                borderRadius:9, padding:'10px 14px', fontSize:13, color:'#085041', marginBottom:12 },
  card:       { background:'#fff', border:'1px solid rgba(13,122,106,0.15)', borderRadius:14,
                padding:16, marginBottom:14 },
  sectionTitle:{ fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:15, marginBottom:12 },
  orderRow:   { display:'flex', justifyContent:'space-between', alignItems:'center',
                padding:'10px 0', borderBottom:'1px solid rgba(0,0,0,0.05)' },
  orderId:    { fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:13 },
  orderMeta:  { fontSize:12, color:'#6b8080', marginTop:2 },
  orderFee:   { fontFamily:'Syne,sans-serif', fontWeight:700, color:'#0D7A6A', fontSize:14 },
  payoutBtn:  { width:'100%', padding:'13px 0', background:'transparent', color:'#0D7A6A',
                border:'1px solid rgba(13,122,106,0.3)', borderRadius:10, fontSize:14,
                fontWeight:600, cursor:'pointer' },
};
